-- Banka hesabi transferi ornegi
CREATE TABLE accounts (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    owner TEXT,
    balance REAL
);

INSERT INTO accounts (owner, balance) VALUES
    ('Ahmet', 1000.00),
    ('Ayse', 500.00);

-- Transaction baslat
BEGIN TRANSACTION;

-- Ahmet'ten 200 TL cikar
UPDATE accounts SET balance = balance - 200 WHERE owner = 'Ahmet';

-- Ayse'ye 200 TL ekle
UPDATE accounts SET balance = balance + 200 WHERE owner = 'Ayse';

-- Her sey basariliysa kaydet
COMMIT;

-- Eger bir hata olursa geri al
-- ROLLBACK;

-- Sonucu kontrol et
SELECT * FROM accounts;

-- SAVEPOINT kullanimi (kismi geri alma)
BEGIN TRANSACTION;
UPDATE accounts SET balance = balance - 100 WHERE owner = 'Ahmet';
SAVEPOINT before_second_update;
UPDATE accounts SET balance = balance + 100 WHERE owner = 'Ayse';
-- ROLLBACK TO before_second_update;
COMMIT;

-- Final durum
SELECT * FROM accounts;
